def num_decodings(s: str) -> int:
    if not s or s[0] == '0':
        return 0

    prev2, prev1 = 1, 1  # dp[0], dp[1]

    for i in range(1, len(s)):
        curr = 0
        if s[i] != '0':
            curr += prev1
        two = int(s[i - 1:i + 1])
        if 10 <= two <= 26:
            curr += prev2
        prev2, prev1 = prev1, curr

    return prev1

function numDecodings(s) {
    if (!s || s[0] === '0') return 0;
    let prev2 = 1, prev1 = 1;
    for (let i = 1; i < s.length; i++) {
        let curr = 0;
        if (s[i] !== '0') curr += prev1;
        const two = parseInt(s.slice(i - 1, i + 1));
        if (two >= 10 && two <= 26) curr += prev2;
        [prev2, prev1] = [prev1, curr];
    }
    return prev1;
}
